import React, { useEffect, useRef } from 'react';

const VideoFrame = ({ src, onError }) => {
  const containerRef = useRef(null);

  useEffect(() => {
    if (src && containerRef.current) {
      // Crear iframe de forma muy básica para evitar detección
      const frame = document.createElement('iframe');

      // Solo atributos esenciales
      frame.src = src;
      frame.width = '100%';
      frame.height = '100%';
      frame.allowFullscreen = true;

      // Sin sandbox ni otros atributos que detectan
      frame.style.border = 'none';
      frame.style.background = '#000';
      frame.style.borderRadius = '8px';

      // Limpiar y agregar
      containerRef.current.innerHTML = '';
      containerRef.current.appendChild(frame);

      // Verificar si carga
      const checkLoad = setTimeout(() => {
        try {
          if (!frame.contentWindow) {
            console.log('Iframe no cargó correctamente');
            if (onError) onError();
          }
        } catch (e) {
          console.log('Error verificando iframe:', e.message);
          if (onError) onError();
        }
      }, 5000);

      return () => {
        clearTimeout(checkLoad);
        if (containerRef.current) {
          containerRef.current.innerHTML = '';
        }
      };
    }
  }, [src, onError]);

  return (
    <div 
      ref={containerRef}
      className="w-full h-96 md:h-[500px] lg:h-[600px] bg-black rounded-lg"
      style={{ minHeight: '400px' }}
    />
  );
};

export default VideoFrame;
